#include <bits/stdc++.h>
using namespace std;

const int N=1010,INF=0x3f3f3f3f;

int n,m,k,p[N][N],x[N],y[N],a[N],f[1<<20];

inline int cal(int i,int x,int y){
    int res=0;
    if(~p[x-1][y] && ((i>>p[x-1][y]*2)&3))
        res+=(1<<p[x-1][y]*2);
    if(~p[x][y-1] && ((i>>p[x][y-1]*2)&3))
        res+=(1<<p[x][y-1]*2);
    if(~p[x][y] && ((i>>p[x][y]*2)&3))
        res+=(1<<p[x][y]*2);
    if(~p[x][y+1] && ((i>>p[x][y+1]*2)&3))
        res+=(1<<p[x][y+1]*2);
    if(~p[x+1][y] && ((i>>p[x+1][y]*2)&3))
        res+=(1<<p[x+1][y]*2);
    return i-res;
}

void Update(int &x,int y){
    x=(x<y?x:y);
}

int main(){
    memset(p,-1,sizeof(p));
    scanf("%d%d%d",&n,&m,&k);
    int sum=0;
    for(int i=0;i<k;i++){
        scanf("%d%d%d",&x[i],&y[i],&a[i]);
        p[x[i]][y[i]]=i;
        sum+=(1<<i+i)*a[i];
    }
    memset(f,0x3f,sizeof(f));
    f[sum]=0;
    for(int i=sum;i;i--){
        if(f[i]==INF)
            continue;
        for(int j=0;j<k;j++){
            if(!((i>>j+j)&3))
                continue;
            Update(f[cal(i,x[j],y[j])],f[i]+1);
            if(x[j]>1)
                Update(f[cal(i,x[j]-1,y[j])],f[i]+1);
            Update(f[cal(i,x[j]+1,y[j])],f[i]+1);
            if(y[j]>1)
                Update(f[cal(i,x[j],y[j]-1)],f[i]+1);
            Update(f[cal(i,x[j],y[j]+1)],f[i]+1);
        }
    }
    printf("%d",f[0]);
    return 0;
}
